const pr = $json.body.pull_request;
const repo = $json.body.repository;

return [{
  json: {
    pr_number: pr.number,
    pr_title: pr.title,
    pr_body: pr.body || '',
    pr_url: pr.html_url,
    pr_diff_url: pr.diff_url,
    repo_full_name: repo.full_name,
    author: pr.user.login,
    base_branch: pr.base.ref,
    head_branch: pr.head.ref,
    changed_files: pr.changed_files,
    additions: pr.additions,
    deletions: pr.deletions,
    commits_url: pr.commits_url,
    review_comments_url: pr.review_comments_url,
    comments_url: pr.comments_url
  }
}];

const files = $json;
const prData = $('Extract PR Data').item.json;

// Build a summary of changed files for the security agent
const fileSummary = files
  .slice(0, 20) // limit to 20 files to stay within token limits
  .map(f => `${f.status.toUpperCase()}: ${f.filename} (+${f.additions}/-${f.deletions})\n${(f.patch || '').slice(0, 500)}`)
  .join('\n\n---\n\n');

const message = `Please perform a security review of this Pull Request:

**PR #${prData.pr_number}: ${prData.pr_title}**
Author: ${prData.author}
Branch: ${prData.head_branch} → ${prData.base_branch}
Changed files: ${prData.changed_files} (+${prData.additions}/-${prData.deletions})

PR Description:
${prData.pr_body || 'No description provided'}

## Changed Files (patches):
${fileSummary}

Provide:
1. Security risk level (LOW/MEDIUM/HIGH/CRITICAL)
2. List of specific security concerns found
3. Recommendations for each concern
4. Overall approval recommendation`;

return [{
  json: {
    ...prData,
    security_prompt: message,
    files_count: files.length
  }
}];

const agentResult = $json.data?.messages?.find(m => m.role === 'assistant')?.content || 'Security review completed.';
const prData = $('Build Security Prompt').item.json;

// Detect risk level from agent response
const riskMatch = agentResult.match(/\b(CRITICAL|HIGH|MEDIUM|LOW)\b/i);
const riskLevel = riskMatch ? riskMatch[1].toUpperCase() : 'UNKNOWN';

const riskEmoji = {
  CRITICAL: '🚨',
  HIGH: '⚠️',
  MEDIUM: '🟡',
  LOW: '✅',
  UNKNOWN: '🔍'
}[riskLevel];

const comment = `## ${riskEmoji} Agent Studio Security Review\n\n**Risk Level: ${riskLevel}**\n\n${agentResult}\n\n---\n*Automated review by [Agent Studio](${process.env.AGENT_STUDIO_URL}) Security Scanner*`;

return [{
  json: {
    pr_number: prData.pr_number,
    repo_full_name: prData.repo_full_name,
    comment_body: comment,
    risk_level: riskLevel
  }
}];
